import { useState, useEffect } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

// Importet e reja për Supabase
import { supabase } from './supabaseClient';
import Auth from './Auth';
import SavedDupes from './SavedDupes';

function App() {
  // Pjesa e AI (Ajo që kishe)
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState("");

  // Pjesa e Supabase (E reja)
  const [session, setSession] = useState(null);

  // Kontrollon nëse user-i është i loguar sapo hapet faqja
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
  }, []);

  // Funksioni yt i Chat-it
  const handleSubmit = async () => {
    if (!input.trim()) return;
    setLoading(true);

    try {
      const res = await fetch("http://localhost:8000/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ message: input }),
      });

      if (!res.ok) {
        throw new Error(`HTTP error! status: ${res.status}`);
      }

      const data = await res.json();
      setResponse(data.reply);
    } catch (error) {
      console.error("Error fetching data:", error);
      setResponse("An error occurred while fetching the response. Make sure your backend is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: "800px", margin: "auto", padding: "40px", fontFamily: "sans-serif" }}>
      <h1 style={{ textAlign: "center", color: "#333" }}>GlowAI 🧴✨</h1>

      {/* Kushti: Nëse nuk ka session (nuk është i loguar), shfaq formën e Loginit */}
      {!session ? (
        <Auth />
      ) : (
        /* Nëse ËSHTË i loguar, shfaq Chat-in dhe Produktet e ruajtura */
        <>
          <div style={{ marginBottom: "50px" }}>
            <h2 style={{ fontSize: "1.2rem", color: "#555" }}>Kërko për Dupes:</h2>
            <textarea
              rows="4"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="E.g., Find a drugstore dupe for Drunk Elephant Protini Cream..."
              style={{ 
                width: "100%", 
                padding: "12px", 
                borderRadius: "8px", 
                border: "1px solid #ccc", 
                fontSize: "16px",
                fontFamily: "inherit"
              }}
            />
            <br />

            <button 
              onClick={handleSubmit} 
              disabled={loading}
              style={{ 
                marginTop: "10px", 
                padding: "10px 20px", 
                backgroundColor: loading ? "#ccc" : "#000", 
                color: "#fff", 
                border: "none", 
                borderRadius: "5px", 
                cursor: loading ? "not-allowed" : "pointer",
                fontSize: "16px"
              }}
            >
              {loading ? "Analyzing Ingredients..." : "Find Dupes"}
            </button>

            {response && (
              <div style={{ 
                marginTop: "30px", 
                padding: "20px", 
                border: "1px solid #eee", 
                borderRadius: "8px", 
                backgroundColor: "#fcfcfc",
                lineHeight: "1.6"
              }}>
                <h3 style={{ marginTop: 0 }}>Analysis:</h3>
                <ReactMarkdown remarkPlugins={[remarkGfm]}>
                  {response}
                </ReactMarkdown>
              </div>
            )}
          </div>

          {/* Vizë ndarëse midis AI-t dhe Databazës */}
          <hr style={{ border: "0", height: "1px", backgroundColor: "#ddd", marginBottom: "40px" }} />

          {/* Forma e re ku përdoruesi shton dhe ruan të dhënat e tij */}
          <SavedDupes session={session} />
        </>
      )}
    </div>
  );
}

export default App;
